// PARSEAR SOLICITUD DE RECOGIDA DESDE UN CORREO DE TEXTO LIBRE

// 1) Obtener texto del correo (HTML o texto plano)
let raw = $json.text || $json.body || $json.bodyPreview || '';

// Si viene en HTML, quitar etiquetas básicas
raw = String(raw)
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/\s+/g, ' ')
  .trim();

const textoOriginal = raw;
const text = textoOriginal.toLowerCase();

function extraer(regexes, parseFn = v => v) {
  for (const r of regexes) {
    const m = text.match(r);
    if (m && m[1]) return parseFn(m[1].trim());
  }
  return null;
}

const codigo_cliente = extraer([
  /codigo\s*cliente[:\-]?\s*([a-z0-9\-]+)/i,
  /c[óo]digo\s*de\s*cliente[:\-]?\s*([a-z0-9\-]+)/i,
  /cliente[:\-]?\s*([a-z0-9\-]+)/i
]);

const cp = extraer([
  /c\.?p\.?\s*[:\-]?\s*(\d{4,5})/i,
  /c[óo]digo\s*postal[:\-]?\s*(\d{4,5})/i
]);

const telefono = extraer([
  /tel[eé]fono[:\-]?\s*([+0-9\s\-]{7,20})/i,
  /tlf[:\-]?\s*([+0-9\s\-]{7,20})/i,
  /m[óo]vil[:\-]?\s*([+0-9\s\-]{7,20})/i
], v => v.replace(/\s+/g, ''));

const palets = extraer([
  /(\d+)\s*(palets?|pallets?|bultos?)/i,
  /palets?[:\-]?\s*(\d+)/i,
  /bultos?[:\-]?\s*(\d+)/i
], v => parseInt(v, 10));

const peso = extraer([
  /peso[:\-]?\s*([\d.,]+)\s*(kg|kgs|kil[oó]s)?/i,
  /([\d.,]+)\s*(kg|kgs|kil[oó]s)/i
], v => parseFloat(v.replace(',', '.')));

const direccion_recogida = extraer([
  /direcci[óo]n\s*de\s*recogida[:\-]?\s*(.+)/i,
  /direcci[óo]n\s*recogida[:\-]?\s*(.+)/i,
  /recoger\s+en[:\-]?\s*(.+)/i
]);

const campos_faltantes = [];
if (!codigo_cliente) campos_faltantes.push('código de cliente');
if (!direccion_recogida) campos_faltantes.push('dirección de recogida');
if (!cp) campos_faltantes.push('código postal');
if (!palets) campos_faltantes.push('número de palets/bultos');
if (!peso) campos_faltantes.push('peso');
if (!telefono) campos_faltantes.push('teléfono');

return {
  codigo_cliente,
  direccion_recogida,
  cp,
  palets,
  peso,
  telefono,
  campos_faltantes,
  es_valido: campos_faltantes.length === 0,
  raw_text: textoOriginal,
  from: $json.from,
  subject: $json.subject
};

