// PROCESAR LA SALIDA DEL AI AGENT Y DEVOLVER JSON LIMPIO
// El agente suele devolver un string con un bloque ```json ... ```.
// Aquí extraemos ese bloque y hacemos JSON.parse para que el resto del flujo
// pueda usar directamente las propiedades (es_valido, campos_faltantes, etc.).

let raw = $json.output || $json.text || $json.response || '';
raw = String(raw).trim();

let jsonString = raw;

// Intentar extraer bloque ```json ... ``` si existe
const match = raw.match(/```json\s*([\s\S]*?)\s*```/i);
if (match && match[1]) {
  jsonString = match[1];
}

let parsed;
try {
  parsed = JSON.parse(jsonString);
} catch (e) {
  // Fallback seguro: marcamos como no válido y devolvemos info de depuración
  parsed = {
    codigo_cliente: null,
    direccion_recogida: null,
    cp: null,
    palets: null,
    peso: null,
    telefono: null,
    campos_faltantes: [
      'código de cliente',
      'dirección de recogida',
      'código postal',
      'número de palets/bultos',
      'peso',
      'teléfono'
    ],
    es_valido: false,
    error_parseo: e.message,
    raw_output: raw
  };
}

return parsed;

// Fusionar datos de Procesar Respuesta AI con resultado de validación Postgres
const ai = $('Procesar Respuesta AI').first().json;
const pg = $json;
const parsear = $('Parsear Solicitud Recogida').first().json;
return {
  ...ai,
  cliente_existe: pg.cliente_existe === true || pg.cliente_existe === 't',
  from: parsear.from,
  subject: parsear.subject
};
